<?php
namespace App\Modules\Drivers\Application\StateMachines;
use InvalidArgumentException;
final class DriverTripStateMachine { public const READY='ready'; public const ASSIGNED='assigned'; public const ACCEPTED='accepted'; public const STARTED='started'; public const PICKUP='pickup'; public const BOARDING='boarding'; public const ON_ROUTE='on_route'; public const DROP_OFF='drop_off'; public const COMPLETED='completed'; public const CANCELLED='cancelled'; public const FAILED='failed'; private const MAP=[self::READY=>[self::ASSIGNED,self::CANCELLED],self::ASSIGNED=>[self::ACCEPTED,self::CANCELLED,self::FAILED],self::ACCEPTED=>[self::STARTED,self::CANCELLED],self::STARTED=>[self::PICKUP,self::CANCELLED,self::FAILED],self::PICKUP=>[self::BOARDING,self::CANCELLED],self::BOARDING=>[self::ON_ROUTE,self::CANCELLED],self::ON_ROUTE=>[self::DROP_OFF,self::FAILED],self::DROP_OFF=>[self::COMPLETED],self::COMPLETED=>[],self::CANCELLED=>[],self::FAILED=>[]]; public function transition(string $from,string $to): string { if($from===$to) return $to; if(!in_array($to,self::MAP[$from]??[],true)) throw new InvalidArgumentException("Invalid trip transition {$from} -> {$to}"); return $to; }}
